import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { val = v; }
    }

    private static void addBoundaryLeft(Node node, StringBuilder sb) {
        if (node == null || (node.left == null && node.right == null)) return;
        sb.append(node.val).append(' ');
        if (node.left != null) addBoundaryLeft(node.left, sb);
        else addBoundaryLeft(node.right, sb);
    }

    private static void addBoundaryRight(Node node, StringBuilder sb) {
        if (node == null || (node.left == null && node.right == null)) return;
        if (node.right != null) addBoundaryRight(node.right, sb);
        else addBoundaryRight(node.left, sb);
        sb.append(node.val).append(' ');
    }

    private static void addLeaves(Node node, StringBuilder sb) {
        if (node == null) return;
        addLeaves(node.left, sb);
        if (node.left == null && node.right == null) sb.append(node.val).append(' ');
        addLeaves(node.right, sb);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder output = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; tc++) {
            int N = Integer.parseInt(br.readLine().trim());
            Node[] nodes = new Node[N + 1];
            for (int i = 1; i <= N; i++) nodes[i] = new Node(i);
            boolean[] isChild = new boolean[N + 1];
            for (int i = 0; i < N - 1; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                if (dir == 'L') nodes[p].left = nodes[c];
                else nodes[p].right = nodes[c];
                isChild[c] = true;
            }
            Node root = null;
            for (int i = 1; i <= N; i++) if (!isChild[i]) { root = nodes[i]; break; }
            StringBuilder sb = new StringBuilder();
            if (root != null) {
                sb.append(root.val).append(' ');
                addBoundaryLeft(root.left, sb);
                addLeaves(root.left, sb);
                addLeaves(root.right, sb);
                addBoundaryRight(root.right, sb);
            }
            // remove trailing space
            if (sb.length() > 0 && sb.charAt(sb.length() - 1) == ' ') sb.setLength(sb.length() - 1);
            output.append(sb.toString());
            if (tc < T - 1) output.append('\n');
        }
        System.out.print(output.toString());
    }
}

